parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "EcommerceCreatorOutreach",
  "type": "object",
  "required": ["outreach"],
  "properties": {
    "outreach": {
      "type": "object",
      "required": ["subject", "message", "priority", "program", "offer_type", "talking_points"],
      "properties": {
        "subject": {
          "type": "string",
          "description": "Personalized email subject line"
        },
        "message": {
          "type": "string",
          "description": "Full personalized email body"
        },
        "priority": {
          "type": "string",
          "enum": ["normal", "medium", "high"],
          "description": "Outreach priority level"
        },
        "program": {
          "type": "string",
          "enum": ["affiliate", "ambassador", "ugc_creator", "brand_partnership"],
          "description": "Recommended creator program type"
        },
        "offer_type": {
          "type": "string",
          "enum": ["discount_code", "commission", "free_product", "paid_collab", "revenue_share"],
          "description": "Primary incentive offer"
        },
        "talking_points": {
          "type": "array",
          "items": {"type": "string"},
          "description": "Key personalization elements used"
        }
      }
    }
  }
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "CreatorClassification",
  "type": "object",
  "required": ["classification"],
  "properties": {
    "classification": {
      "type": "object",
      "required": ["primary_platform", "tier", "niche", "niche_subcategory", "value_score", "reasoning"],
      "properties": {
        "primary_platform": {
          "type": "string",
          "enum": ["instagram", "tiktok", "youtube", "twitter"],
          "description": "Platform with highest engagement or most relevant audience"
        },
        "tier": {
          "type": "string",
          "enum": ["nano", "micro", "mid", "macro"],
          "description": "Influencer tier based on follower count"
        },
        "tier_name": {
          "type": "string",
          "description": "Human-readable tier name"
        },
        "niche": {
          "type": "string",
          "enum": [
            "fashion",
            "beauty",
            "fitness",
            "food",
            "home_lifestyle",
            "tech",
            "parenting",
            "travel",
            "pets",
            "business",
            "entertainment",
            "education",
            "art_photography",
            "automotive",
            "sports",
            "gaming",
            "music",
            "general"
          ],
          "description": "Primary content niche"
        },
        "niche_name": {
          "type": "string",
          "description": "Human-readable niche name"
        },
        "niche_subcategory": {
          "type": "string",
          "description": "Specific subcategory within niche (e.g., 'sustainable fashion', 'vegan cooking', 'exotic pets')"
        },
        "followers": {
          "type": "integer",
          "description": "Total follower count from primary platform"
        },
        "engagement_rate": {
          "type": "number",
          "description": "Engagement rate percentage"
        },
        "username": {
          "type": "string",
          "description": "Creator's username on primary platform"
        },
        "profile_url": {
          "type": "string",
          "description": "URL to primary platform profile"
        },
        "value_score": {
          "type": "integer",
          "minimum": 0,
          "maximum": 100,
          "description": "Overall value score for partnership potential (0-100)"
        },
        "content_themes": {
          "type": "array",
          "items": {"type": "string"},
          "maxItems": 5,
          "description": "Key content themes or topics (max 5)"
        },
        "audience_demographics": {
          "type": "string",
          "description": "Likely audience demographics based on content"
        },
        "brand_fit_score": {
          "type": "integer",
          "minimum": 0,
          "maximum": 10,
          "description": "How well they fit for e-commerce brand partnerships (1-10)"
        },
        "reasoning": {
          "type": "string",
          "description": "Brief explanation of classification decisions"
        }
      }
    }
  }
}

parameters.jsCode:
const subscriber = $input.first().json;

return {
  json: {
    email: subscriber.email,
    first_name: subscriber.first_name,
    last_name: subscriber.last_name,
    enrichment_status: 'failed',
    classification: {
      creator_status: 'non_creator',
      creator_type: {},
      creator_tier: { overall: 'none', max_followers: 0 },
      intent_signals: {
        has_affiliate_links: false,
        has_brand_deals: false,
        sells_products_or_subscriptions: false
      },
      platforms_present: []
    },
    routing: {
      flow: 'standard_newsletter',
      priority: 'low',
      actions: ['Keep in standard newsletter flow'],
      notes: 'Enrichment failed - treating as non-creator'
    },
    timestamp: new Date().toISOString()
  }
};

